const pptxgen = require("pptxgenjs");

async function createSimplePresentation() {
  const pptx = new pptxgen();
  pptx.layout = "LAYOUT_16x9";
  pptx.author = "CSP";
  pptx.title = "2025 AX 업무 체계";

  // Define colors
  const colors = {
    primary: "1E3A8A",
    accent: "0D9488",
    highlight: "F59E0B",
    purple: "7C3AED"
  };

  // Slide 1: 표지
  let slide = pptx.addSlide();
  slide.background = { color: colors.primary };
  slide.addText("2025 AX 업무 체계", {
    x: 0.5, y: 1.5, w: 9, h: 1,
    fontSize: 48, bold: true, color: "FFFFFF", align: "center"
  });
  slide.addText("이해통실 기반 생태계 구축 전략", {
    x: 0.5, y: 2.6, w: 9, h: 0.6,
    fontSize: 24, color: "93C5FD", align: "center"
  });
  slide.addText("성과와 성장을 동시에", {
    x: 0.5, y: 4, w: 9, h: 0.4,
    fontSize: 18, color: "93C5FD", align: "center"
  });

  // Slide 2: R&R
  slide = pptx.addSlide();
  slide.addText("2025년 R&R 현황", {
    x: 0.5, y: 0.4, w: 9, h: 0.5,
    fontSize: 36, bold: true, color: colors.primary
  });
  slide.addText([
    { text: "1. 업무·기술역량인증 체계\n", options: { bold: true, fontSize: 18, color: "1F2937" } },
    { text: "   기술 Trend cycle별 체계 개편\n\n", options: { fontSize: 14, color: "6B7280" } },
    { text: "2. AX 업무내재화 (Vibe Coding)\n", options: { bold: true, fontSize: 18, color: "1F2937" } },
    { text: "   빠른 프로토타이핑 기반 조직 확산\n\n", options: { fontSize: 14, color: "6B7280" } },
    { text: "3. Domain AX 인증\n", options: { bold: true, fontSize: 18, color: "1F2937" } },
    { text: "   제조 도메인 전문성 체계화\n\n", options: { fontSize: 14, color: "6B7280" } },
    { text: "4. 제조AX아카데미\n", options: { bold: true, fontSize: 18, color: "1F2937" } },
    { text: "   오퍼레이션 선당/전달당, 직속 조직", options: { fontSize: 14, color: "6B7280" } }
  ], { x: 0.7, y: 1.2, w: 8.5, h: 3.5 });

  // Slide 3: 핵심 포지셔닝
  slide = pptx.addSlide();
  slide.addText("핵심 포지셔닝", {
    x: 0.5, y: 0.4, w: 9, h: 0.5,
    fontSize: 36, bold: true, color: colors.primary
  });
  slide.addText("이해통실 × AX 전도사", {
    x: 0.5, y: 1.5, w: 9, h: 0.8,
    fontSize: 42, bold: true, color: colors.accent, align: "center"
  });
  slide.addText("빠르게 만들되(Vibe coding), 완벽하게 검증하고(이해통실),\n조직에 학습시켜(교육), 플랫폼으로 확산하는(인프라) 사람", {
    x: 1, y: 2.8, w: 8, h: 1,
    fontSize: 16, color: "1F2937", align: "center"
  });

  // Slide 4: 3가지 실행 모드
  slide = pptx.addSlide();
  slide.addText("3가지 실행 모드", {
    x: 0.5, y: 0.4, w: 9, h: 0.5,
    fontSize: 36, bold: true, color: colors.primary
  });

  // Column 1
  slide.addShape(pptx.ShapeType.rect, {
    x: 0.5, y: 1.2, w: 2.8, h: 3,
    fill: { color: "EFF6FF" }
  });
  slide.addText("1. 교육 프로그램", {
    x: 0.6, y: 1.4, w: 2.6, h: 0.4,
    fontSize: 16, bold: true, color: colors.primary
