  slide.addText("리소스: 30%", {
    x: 0.7, y: 3.7, w: 2.4, h: 0.3,
    fontSize: 12, bold: true, color: colors.primary
  });

  // Column 2
  slide.addShape(pptx.ShapeType.rect, {
    x: 3.5, y: 1.2, w: 2.8, h: 3,
    fill: { color: "F0FDF4" }
  });
  slide.addText("2. 자체 프로젝트", {
    x: 3.6, y: 1.4, w: 2.6, h: 0.4,
    fontSize: 16, bold: true, color: colors.accent
  });
  slide.addText("AX 역량 통합 플랫폼\nStarter Kit 라이브러리\n사례 DB & 검색", {
    x: 3.7, y: 1.9, w: 2.4, h: 1.5,
    fontSize: 12, color: "1F2937"
  });
  slide.addText("리소스: 40%", {
    x: 3.7, y: 3.7, w: 2.4, h: 0.3,
    fontSize: 12, bold: true, color: colors.accent
  });

  // Column 3
  slide.addShape(pptx.ShapeType.rect, {
    x: 6.5, y: 1.2, w: 2.8, h: 3,
    fill: { color: "FEF3C7" }
  });
  slide.addText("3. 현업 과제 지원", {
    x: 6.6, y: 1.4, w: 2.6, h: 0.4,
    fontSize: 16, bold: true, color: colors.highlight
  });
  slide.addText("Rapid Prototyping\nAX 전문가 풀\nAX Clinic", {
    x: 6.7, y: 1.9, w: 2.4, h: 1.5,
    fontSize: 12, color: "1F2937"
  });
  slide.addText("리소스: 25%", {
    x: 6.7, y: 3.7, w: 2.4, h: 0.3,
    fontSize: 12, bold: true, color: colors.highlight
  });

  // Slide 5: 이해통실 프레임워크
  slide = pptx.addSlide();
  slide.addText("이해통실 프레임워크란?", {
    x: 0.5, y: 0.4, w: 9, h: 0.5,
    fontSize: 36, bold: true, color: colors.purple
  });
  slide.addText("일과 의사결정의 완성도를 99.99%까지 높이는\nH&A 본부의 핵심 일하는 방식 혁신 프레임워크", {
    x: 1, y: 1.3, w: 8, h: 0.6,
    fontSize: 14, color: "1F2937", align: "center"
  });

  const frameworks = [
    { title: "理 이론", subtitle: "원리·메커니즘", desc: "왜 이렇게 작동하는가?", x: 0.8, color: colors.purple },
    { title: "解 해석", subtitle: "시뮬레이션·모델링", desc: "다른 케이스에선 어떨까?", x: 3, color: "06B6D4" },
    { title: "統 통계", subtitle: "데이터 기반 검증", desc: "실제 성과는 얼마나?", x: 5.2, color: "10B981" },
    { title: "實 실험", subtitle: "현장 테스트", desc: "정말 작동하나?", x: 7.4, color: colors.highlight }
  ];

  frameworks.forEach(fw => {
    slide.addShape(pptx.ShapeType.ellipse, {
      x: fw.x, y: 2.3, w: 0.7, h: 0.7,
      fill: { color: fw.color }
    });
    slide.addText(fw.title.split(' ')[0], {
      x: fw.x, y: 2.45, w: 0.7, h: 0.4,
      fontSize: 20, bold: true, color: "FFFFFF", align: "center"
    });
    slide.addText(fw.title.split(' ')[1], {
      x: fw.x - 0.2, y: 3.1, w: 1.1, h: 0.3,
      fontSize: 14, bold: true, color: "1F2937", align: "center"
    });
    slide.addText(fw.subtitle, {
      x: fw.x - 0.2, y: 3.4, w: 1.1, h: 0.25,
      fontSize: 11, color: "6B7280", align: "center"
    });
    slide.addText(fw.desc, {
      x: fw.x - 0.3, y: 3.7, w: 1.3, h: 0.3,
      fontSize: 10, color: "6B7280", align: "center"
    });
