    { q: "Q4 고도화", items: ["인증 100명", "플랫폼 통합", "SaaS 준비"], x: 7.6, color: "F5F3FF" }
  ];

  quarters.forEach(qtr => {
    slide.addShape(pptx.ShapeType.rect, {
      x: qtr.x, y: 1.3, w: 2, h: 2.8,
      fill: { color: qtr.color }
    });
    slide.addText(qtr.q, {
      x: qtr.x + 0.1, y: 1.4, w: 1.8, h: 0.4,
      fontSize: 14, bold: true, color: "1F2937", align: "center"
